"use client"


import ServiceCard from "@/componenten/Cards/ServiceCard"
import Hero from "@/componenten/Hero"
import Navbar from "@/componenten/Navbar"
import { useEffect, useState } from "react"

export default function Home() {

  const [scrolled, setScrolled] = useState(false)

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 80)
    }

    window.addEventListener("scroll", handleScroll)

    return () => window.removeEventListener("scroll", handleScroll)
  }, [])

  return (

    <main className="bg-white">
      <Navbar />
      <Hero />
      {/* SERVICES */}
      <section className="pt-56 pb-20 bg-gray-50">

        <div className="max-w-7xl mx-auto px-10">

          <h2 className="text-4xl font-bold text-center text-slate-800 mb-16">
            Nos services de nettoyage
          </h2>

          <div className="grid md:grid-cols-4 gap-8">

            <ServiceCard
            icon="🏢"
            title="Immeuble"
            description=" Nettoyage complet des parties communes  et des espaces résidentiels."
            onClick={()=>console.log("Immeuble")}
            />
            <ServiceCard
            icon="🚗"
            title="Voiture"
            description="Lavage intérieur et extérieur pour
                redonner éclat à votre véhicule."
            onClick={()=>console.log("Voiture")}
            />

             <ServiceCard
            icon="🏢"
            title="Bureau"
            description="Nettoyage professionnel des bureaux
                pour un environnement de travail sain."
            onClick={()=>console.log("Bureau")}
            />

              <ServiceCard
            icon="🛋"
            title="Meuble"
            description="Entretien et nettoyage de vos meubles
                et surfaces délicates."
            onClick={()=>console.log("Meuble")}
            />
          </div>

        </div>

      </section>


    </main>
  )
}